// category.service.ts - AGGIORNAMENTO
import { Injectable, inject } from '@angular/core';
import { BaseService } from '../Base/base.service';
import { map, Observable, take, of, catchError } from 'rxjs';
import { Category } from '../../models';

@Injectable({ providedIn: 'root' })
export class CategoryService extends BaseService<Category> {
  protected getTableName(): string {
    return 'categories';
  }

  // Metodo pubblico per ottenere restaurantId (se serve)
public async getRestaurantId(): Promise<string | null> {
  return await this.getCurrentRestaurantId();
}


getCategoriesForOrderEditor(): Observable<Category[]> {
  return this.data$.pipe(
    catchError(error => {
      console.warn('⚠️ Errore categorie, usando default:', error);
      return of(this.getDefaultCategories());
    })
  );
}

private getDefaultCategories(): Category[] {
  return [
    { id: 'antipasti', name: 'Antipasti', order_index: 1, is_default: false, restaurant_id: '' } as Category,
    { id: 'primi', name: 'Primi', order_index: 2, is_default: false, restaurant_id: '' } as Category,
    { id: 'secondi', name: 'Secondi', order_index: 3, is_default: false, restaurant_id: '' } as Category,
    { id: 'dessert', name: 'Dessert', order_index: 4, is_default: false, restaurant_id: '' } as Category,
    { id: 'bevande', name: 'Bevande', order_index: 5, is_default: false, restaurant_id: '' } as Category
  ];
}

  // ✅ NUOVO: Sovrascrivi loadData per gestire errori 403
  override async loadData(): Promise<void> {
    try {
      const restaurantId = await this.getCurrentRestaurantId();
      
      if (!restaurantId) {
        console.warn('⚠️ Nessun restaurantId trovato per CategoryService');
        this.dataSubject.next([]);
        return;
      }

      console.log('📋 Caricamento categorie per restaurant:', restaurantId);
      
      this.loadingService.start();
      
      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .select('*')
        .eq('restaurant_id', restaurantId)
        .order('order_index', { ascending: true });

      if (error) {
        // Gestione specifica errore 403
        if (error.code === '42501' || error.message.includes('403')) {
          console.error('❌ Errore autorizzazione (403) per categorie:', error.message);
          this.errorSubject.next('Non hai i permessi per visualizzare le categorie');
          this.dataSubject.next(this.getDefaultCategories()); // Fallback a categorie di default
        } else {
          throw error;
        }
      } else {
        console.log(`✅ Categorie caricate: ${data?.length || 0}`);
        this.dataSubject.next(data || []);
      }
      
    } catch (error: any) {
      console.error('❌ Errore caricamento categorie:', error);
      this.errorSubject.next(error.message || 'Errore caricamento categorie');
      this.dataSubject.next(this.getDefaultCategories()); // Fallback
    } finally {
      this.loadingService.stop();
    }
  }

getCategories(): Category[] {
  return this.dataSubject.value;
}

  // ✅ NUOVO: Metodo specifico per order-editor
  getCategoriesForEditor(): Observable<Category[]> {
    return this.data$.pipe(
      catchError(error => {
        console.warn('⚠️ Errore categorie, usando fallback:', error);
        return of(this.getDefaultCategories());
      })
    );
  }

  // Metodo per creare categoria (semplificato)
async createCategory(categoryData: {
  name: string;
  description?: string;
  is_default?: boolean;
  order_index?: number; // AGGIUNGI QUESTO
}): Promise<Category | null> {
  try {
    console.log('📝 Creazione categoria:', categoryData);

    // 1. Validazione
    if (!categoryData.name || categoryData.name.trim() === '') {
      this.errorSubject.next('Il nome della categoria è obbligatorio');
      return null;
    }

    // 2. Ottieni restaurantId
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) {
      console.error('❌ Nessun restaurantId trovato');
      this.errorSubject.next('Nessun ristorante selezionato');
      return null;
    }

    // 3. Calcola order_index se non fornito
    let orderIndex = categoryData.order_index;
    
    if (orderIndex === undefined || orderIndex === null) {
      try {
        const { data, error } = await this.supabaseService.getSupabaseClient()
          .from('categories')
          .select('order_index')
          .eq('restaurant_id', restaurantId)
          .order('order_index', { ascending: false })
          .limit(1);

        if (!error && data && data.length > 0) {
          orderIndex = data[0].order_index + 1;
        } else {
          orderIndex = 1; // Prima categoria
        }
      } catch (error) {
        console.warn('⚠️ Errore calcolo order_index, usando 1:', error);
        orderIndex = 1;
      }
    }

    // 4. Prepara dati per l'inserimento
    const categoryToInsert = {
      name: categoryData.name.trim(),
      description: categoryData.description?.trim() || null,
      is_default: categoryData.is_default || false,
      order_index: orderIndex, // Usa quello calcolato o fornito
      restaurant_id: restaurantId,
      created_at: new Date().toISOString(),
      updated_at: new Date().toISOString()
    };

    console.log('📤 Inserimento categoria:', categoryToInsert);

    // 5. Inserisci
    const { data, error } = await this.supabaseService.getSupabaseClient()
      .from('categories')
      .insert(categoryToInsert)
      .select()
      .single();

    if (error) {
      console.error('💥 [ERROR] Errore Supabase:', error);
      this.errorSubject.next(error.message || 'Errore creazione categoria');
      return null;
    }

    console.log('✅ Categoria creata:', data);
    
    // 6. Ricarica i dati
    await this.loadData();
    
    return data as Category;

  } catch (error: any) {
    console.error('💥 Errore inatteso creazione categoria:', error);
    this.errorSubject.next(error.message || 'Errore inatteso');
    return null;
  }
}



// Metodo alias per compatibilità
async createCategoryForCurrentUser(categoryData: {
  name: string;
  description?: string;
  is_default?: boolean;
}): Promise<Category | null> {
  return this.createCategory(categoryData);
}


getRestaurantId$(): Observable<string | null> {
  return new Observable<string | null>(subscriber => {
    this.getRestaurantId()
      .then(id => {
        subscriber.next(id);
        subscriber.complete();
      })
      .catch(err => subscriber.error(err));
  });
}


async getNextAvailableOrderIndex(): Promise<number> {
  try {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return 0;

    const { data, error } = await this.supabaseService.getSupabaseClient()
      .from('categories')
      .select('order_index')
      .eq('restaurant_id', restaurantId)
      .order('order_index', { ascending: false })
      .limit(1);

    if (error) {
      console.warn('⚠️ Errore recupero ultimo order_index:', error);
      return 0;
    }

    if (data && data.length > 0) {
      return (data[0].order_index || 0) + 1;
    }

    return 0;
  } catch (error) {
    console.error('❌ Errore in getNextAvailableOrderIndex:', error);
    return 0;
  }
}

async getCategoryOrderList(): Promise<{id: string, name: string, order_index: number}[]> {
  try {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return [];

    const { data, error } = await this.supabaseService.getSupabaseClient()
      .from('categories')
      .select('id, name, order_index')
      .eq('restaurant_id', restaurantId)
      .order('order_index', { ascending: true });

    if (error) throw error;
    return data || [];
  } catch (error) {
    console.error('❌ Errore recupero ordine categorie:', error);
    return [];
  }
}

async updateCategoriesOrder(updates: {id: string, order_index: number}[]): Promise<boolean> {
  try {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return false;

    // Assicurati che gli order_index siano almeno 1
    const normalizedUpdates = updates.map(update => ({
      ...update,
      order_index: Math.max(1, update.order_index)
    }));

    console.log('📤 Aggiornamento ordine categorie:', normalizedUpdates);
    
    // Crea le query per aggiornare in batch
    const updatePromises = normalizedUpdates.map(update => 
      this.supabaseService.getSupabaseClient()
        .from('categories')
        .update({ 
          order_index: update.order_index,
          updated_at: new Date().toISOString()
        })
        .eq('id', update.id)
        .eq('restaurant_id', restaurantId)
    );

    // Esegui tutte le update
    const results = await Promise.all(updatePromises);
    
    // Controlla errori
    const hasError = results.some(result => result.error);
    
    if (hasError) {
      console.error('❌ Errore durante l\'aggiornamento dell\'ordine');
      return false;
    }

    // Ricarica i dati
    await this.loadData();
    console.log('✅ Ordine categorie aggiornato con successo');
    return true;
    
  } catch (error) {
    console.error('💥 Errore in updateCategoriesOrder:', error);
    return false;
  }
}


// Metodo per aggiornare una singola categoria
async updateCategory(categoryId: string, data: Partial<Category>): Promise<Category | null> {
  try {
    const { data: updatedCategory, error } = await this.supabaseService.getSupabaseClient()
      .from('categories')
      .update({
        ...data,
        updated_at: new Date().toISOString()
      })
      .eq('id', categoryId)
      .select()
      .single();

    if (error) throw error;
    
    // Ricarica i dati
    await this.loadData();
    return updatedCategory as Category;
    
  } catch (error) {
    console.error('❌ Errore aggiornamento categoria:', error);
    return null;
  }
}

}